#include <iostream>
#include <string>
using namespace std;

class Student {
private:
    string name;
    int age;
    double gpa;

public:
    // Constructor
    Student(string n, int a, double g) {
        name = n;
        age = a;
        gpa = g;
    }

    // Public member functions (getters)
    string getName() {
        return name;
    }

    int getAge() {
        return age;
    }

    double getGPA() {
        return gpa;
    }

    // Public member function (setter)
    void setGPA(double newGpa) {
        if (newGpa >= 0.0 && newGpa <= 4.0) {
            gpa = newGpa;
        }
    }

    void display() {
        cout << "Name: " << name << endl;
        cout << "Age: " << age << endl;
        cout << "GPA: " << gpa << endl;
    }
};

int main() {
    Student s1("John Doe", 20, 3.75);
    s1.display();

    cout << "\nUpdating GPA..." << endl;
    s1.setGPA(3.9);
    s1.display();

    // These would cause errors:
    // s1.name = "Jane";  // Error: name is private
    // s1.age = 21;       // Error: age is private

    return 0;
}

#include <iostream>
using namespace std;

// Base class
class Person {
protected:
    string name;
    int age;

public:
    Person(string n, int a) {
        name = n;
        age = a;
    }

    void displayPerson() {
        cout << "Name: " << name << endl;
        cout << "Age: " << age << endl;
    }
};

// Derived class - inherits from Person
class Student : public Person {
private:
    int studentID;
    double gpa;

public:
    Student(string n, int a, int id, double g) : Person(n, a) {
        studentID = id;
        gpa = g;
    }

    // Can access protected members from base class
    string getName() {
        return name;  // OK: accessing protected member
    }

    int getAge() {
        return age;  // OK: accessing protected member
    }

    void displayStudent() {
        displayPerson();  // Call base class method
        cout << "Student ID: " << studentID << endl;
        cout << "GPA: " << gpa << endl;
    }
};

// Another derived class
class Teacher : public Person {
private:
    string subject;
    double salary;

public:
    Teacher(string n, int a, string sub, double sal) : Person(n, a) {
        subject = sub;
        salary = sal;
    }

    void displayTeacher() {
        displayPerson();
        cout << "Subject: " << subject << endl;
        cout << "Salary: $" << salary << endl;
    }
};

int main() {
    Student s1("Alice", 19, 12345, 3.8);
    Teacher t1("Mr. Smith", 35, "Mathematics", 5000.0);

    cout << "=== Student Info ===" << endl;
    s1.displayStudent();

    cout << "\n=== Teacher Info ===" << endl;
    t1.displayTeacher();

    // These would cause errors:
    // cout << s1.name;  // Error: name is protected
    // s1.age = 20;       // Error: age is protected

    return 0;
}
